def pagerank_simplified(graph, damping_factor=0.85, iterations=100):
    """
    PageRank algoritmasının basitleştirilmiş bir versiyonunu uygular.

    Args:
        graph (dict): Anahtarların sayfa isimleri ve değerlerin
                      o sayfadan çıkan bağlantıların listesi olduğu bir sözlük.
                      Örn: {'A': ['B', 'C'], 'B': ['A'], 'C': ['A']}
        damping_factor (float): Sönümleme faktörü (genellikle 0.85).
        iterations (int): PageRank değerlerini hesaplamak için tekrar sayısı.

    Returns:
        dict: Anahtarların sayfa isimleri ve değerlerin hesaplanmış PageRank
              değerleri olduğu bir sözlük.
    """

    # Tüm benzersiz sayfaları (düğümleri) topla
    all_pages = set(graph.keys())
    for links_out in graph.values():
        all_pages.update(links_out)

    nodes = list(all_pages)
    num_nodes = len(nodes)

    if num_nodes == 0:
        return {}

    # Başlangıç PageRank değerlerini eşittir (1/N) olarak ata
    pageranks = {node: 1.0 / num_nodes for node in nodes}

    for _ in range(iterations):
        new_pageranks = {node: (1.0 - damping_factor) / num_nodes for node in nodes}

        # Bağlantı veren sayfalardan gelen katkıları hesapla
        # Sadece graph anahtarı olan sayfalar bağlantı verebilir
        for page in graph: 
            outgoing_links = graph[page]

            if not outgoing_links:
                # Bağlantısı olmayan (dangling) düğümlerin PageRank'ı tüm sayfalara eşit olarak dağıtılır
                for node in nodes:
                    new_pageranks[node] += damping_factor * pageranks[page] / num_nodes
            else:
                # Normal sayfalar, PageRank'larını bağlandıkları sayfalara dağıtır
                contribution = pageranks[page] / len(outgoing_links)
                for linked_page in outgoing_links:
                    if linked_page in pageranks: # Bağlantı verilen sayfanın mevcut düğümlerden biri olduğundan emin ol
                        new_pageranks[linked_page] += damping_factor * contribution

        pageranks = new_pageranks

    return pageranks
